## VARIABLES
TREE_MAKE := tree.make

##
## _default should always be the first dependency (you can add extra local actions with default::)
##

default: $(TREE_MAKE)

DEFAULT_CPP  := /home/utils/gcc-4.9.3/bin/cpp
DEFAULT_GCC  := /home/utils/gcc-4.9.3/bin/g++
